VALUES ('maths', 'By the properties of the Beta function, $B(m,n)$ is also equal to:', '["$\\int_0^1 x^{n-1} (1-x)^{m-1} dx$", "$\\int_0^1 x^{m} (1-x)^{n} dx$", "$\\int_0^\\infty e^{-x} x^{m+n-1} dx$", "$\\int_0^1 x^{m+n} dx$"]', 0);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'If $B(m,n) = \frac{\Gamma(m)\Gamma(n)}{\Gamma(m+n)}$, what is the denominator when $m=3$ and $n=2$?', '["$\\Gamma(5)$", "$\\Gamma(6)$", "$5!$", "$6!$"]', 0);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'For $m=3, n=2$, what is the numerical value of $\Gamma(m+n)$?', '["$120$", "$24$", "$6$", "$12$"]', 1);

