VALUES ('maths', 'What is the value of $B(3,2)$?', '["$1/12$", "$1/24$", "$1/6$", "$1/2$"]', 0);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'The integral $\int_0^{\pi/2} \sin^3(\theta) \cos^5(\theta) d\theta$ can be solved easily using the Beta function. In the formula $2 \int \sin^{2m-1}(\theta) \cos^{2n-1}(\theta) d\theta = B(m,n)$, what are $m$ and $n$?', '["$m=3, n=5$", "$m=2, n=3$", "$m=1.5, n=2.5$", "$m=4, n=6$"]', 1);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'The function $B(m,n)$ is defined only when:', '["Both $m$ and $n$ are strictly positive.", "Both $m$ and $n$ are non-negative.", "Both $m$ and $n$ are integers.", "Both $m$ and $n$ are strictly greater than 1."]', 0);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'The relationship $B(m,n) = \frac{m-1}{m+n-1} B(m-1,n)$ represents a:', '["Reflection formula", "Reduction property of the Beta function", "Trigonometric identity", "Gamma definition"]', 1);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'Which of the following is equivalent to $B(n, 1)$?', '["$n$", "$1/n$", "$n!$", "$1$"]', 1);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'What does DUIS stand for in calculus?', '["Direct Unification of Integral Sums", "Derivative Under Infinite Series", "Differentiation Under the Integral Sign", "Dual Uniform Integral System"]', 2);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'The DUIS rule is also famously known by the name of which mathematician?', '["Newton''s Rule", "Leibniz''s Rule", "Euler''s Rule", "L''H\u00f4pital''s Rule"]', 1);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'If $I(\alpha) = \int_a^b f(x,\alpha) dx$ where $a$ and $b$ are constants, what does Leibniz''s rule state about $\frac{dI}{d\alpha}$?', '["$\\int_a^b \\frac{df}{dx} dx$", "$\\int_a^b \\frac{\\partial f}{\\partial \\alpha} dx$", "$\\int_a^b f(x,\\alpha) d\\alpha$", "$f(b,\\alpha) - f(a,\\alpha)$"]', 1);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'In the basic DUIS rule with constant limits, the ordinary derivative $\frac{d}{d\alpha}$ outside the integral becomes what kind of derivative inside the integral?', '["Ordinary derivative with respect to $x$", "Partial derivative with respect to $x$", "Partial derivative with respect to $\\alpha$", "Double derivative"]', 2);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'To apply the basic Leibniz rule (constant limits), the limits of integration $a$ and $b$ must be:', '["Variables dependent on $x$", "Variables dependent on $\\alpha$", "Independent of the parameter $\\alpha$", "Zero and Infinity only"]', 2);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'When evaluating $\frac{d}{d\alpha} \int_0^1 e^{\alpha x} dx$ using DUIS, what is the partial derivative $\frac{\partial}{\partial \alpha} (e^{\alpha x})$?', '["$e^{\\alpha x}$", "$\\alpha e^{\\alpha x}$", "$x e^{\\alpha x}$", "$x \\alpha e^{\\alpha x}$"]', 2);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'When evaluating $\frac{d}{d\alpha} \int_0^\pi \cos(\alpha x) dx$ using DUIS, what is $\frac{\partial}{\partial \alpha} \cos(\alpha x)$?', '["$-\\sin(\\alpha x)$", "$-x \\sin(\\alpha x)$", "$-\\alpha \\sin(\\alpha x)$", "$x \\cos(\\alpha x)$"]', 1);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'The extended Leibniz rule applies when:', '["The integrand is a constant", "The integral has no limits", "The limits of integration depend on the parameter being differentiated", "The parameter is a complex number"]', 2);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'If $I(\alpha) = \int_0^\alpha f(x) dx$, then by the fundamental theorem of calculus (which is a simple case of variable-limit DUIS), what is $\frac{dI}{d\alpha}$?', '["$f(x)$", "$f''(\\alpha)$", "$f(\\alpha)$", "$0$"]', 2);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'Which theorem forms the foundation of the DUIS rule for variable limits?', '["Pythagorean Theorem", "Fundamental Theorem of Calculus", "Mean Value Theorem", "Taylor''s Theorem"]', 1);

INSERT INTO questions (subject, question, options, correct_index)
VALUES ('maths', 'Why do we use the DUIS rule?', '["To solve differential equations directly", "To evaluate difficult definite integrals by introducing a parameter", "To convert integrals into sums", "To find the roots of a polynomial"]', 1);

