VALUES ('maths', 'When evaluating $\frac{d}{dy} \int_1^2 (x^2 + y^2) dx$ using DUIS, what is the integrand for the new integral?', '["$2x$", "$2y$", "$x^2 + 2y$", "$2x + 2y$"]', 1);

